import xmltodict
def parse_xml(file):  # Function to Parse An Xml File And Return The Settings As A Dictionary  
    with open (f'{file}.xml', 'r') as file :    
        data = file.read()     
        
    dict_data =  xmltodict.parse(data)      
            
    return  dict_data['root'] # Returning The Settings As A Dictionary